import{_ as o,C as s,o as l,c as n,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Norway Healthcare","description":"Healthcare and HRT access for transgender people in Norway","frontmatter":{"layout":"doc","title":"Norway Healthcare","description":"Healthcare and HRT access for transgender people in Norway"},"headers":[],"relativePath":"europe/norway/healthcare.md","filePath":"europe/norway/healthcare.md","lastUpdated":null}'),h={name:"europe/norway/healthcare.md"};function c(p,e,g,u,y,m){const t=s("Badge");return l(),n("div",null,[r(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[i("Informed Consent Model",-1)])]),_:1}),r(t,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[i("Public Healthcare System",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-norway" tabindex="-1">Healthcare in Norway <a class="header-anchor" href="#healthcare-in-norway" aria-label="Permalink to &quot;Healthcare in Norway&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Norway&#39;s gender affirming healthcare is primarily centralised at <strong>Oslo University Hospital (OUS) - Rikshospitalet</strong>, through the <strong>National Treatment Service for Gender Incongruence (NBTS)</strong>. The model has shifted toward informed consent in recent years, though some structured psychological assessment remains.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><p>Hormone therapy in Norway has become increasingly accessible:</p><ul><li>Self-referral to NBTS or referral through a GP</li><li>Initial assessment (typically 1-3 sessions with psychologist/psychiatrist)</li><li>No longer requires a formal diagnosis of gender dysphoria for hormone access</li><li>Treatment is free through the public system</li><li>Typical wait times: 4-12 months for initial assessment</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Languages</th><th>Wait Times</th></tr></thead><tbody><tr><td>NBTS - Oslo University Hospital (Rikshospitalet)</td><td>Oslo</td><td>HRT, surgery, psychological assessment</td><td>NO, EN</td><td>6-12 months</td></tr><tr><td>Haukeland University Hospital</td><td>Bergen</td><td>HRT, referrals</td><td>NO, EN</td><td>8-14 months</td></tr><tr><td>St. Olav&#39;s Hospital</td><td>Trondheim</td><td>HRT, referrals</td><td>NO, EN</td><td>8-14 months</td></tr><tr><td>Private endocrinologists</td><td>Oslo, Bergen, Trondheim</td><td>HRT (limited, with NBTS coordination)</td><td>NO, EN</td><td>1-3 months</td></tr></tbody></table><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender affirming surgeries are covered by the public healthcare system:</p><ul><li><strong>Chest/breast surgery (top surgery)</strong> — Fully covered, wait times 6-12 months</li><li><strong>Genital surgery (bottom surgery)</strong> — Available at OUS-Rikshospitalet, 1-2 year wait</li><li><strong>Facial feminisation surgery</strong> — Limited public coverage, typically self-funded</li><li><strong>Hysterectomy/oophorectomy</strong> — Covered</li><li><strong>Voice surgery</strong> — Limited availability</li></ul><p>The NBTS coordinates all surgical referrals. There is a national waiting list for surgeries.</p><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EEA member, Norway recognises prescriptions from EU/EEA countries:</p><ul><li>Valid for up to 30 days</li><li>English or Scandinavian language prescriptions recommended</li><li>Ongoing medications should be re-prescribed by a Norwegian GP</li><li>Emergency supply possible from pharmacy in urgent cases</li></ul><table tabindex="0"><thead><tr><th>Medication</th><th>Typical Cost (public)</th><th>Pharmacy Availability</th></tr></thead><tbody><tr><td>Oestradiol (oral/gel/patches)</td><td>~€5-15/month (after deductible)</td><td>Widely available</td></tr><tr><td>Testosterone (gel/injectable)</td><td>~€10-25/month (after deductible)</td><td>Widely available</td></tr><tr><td>Cyproterone acetate</td><td>~€8-18/month (after deductible)</td><td>Available</td></tr><tr><td>GnRH agonists</td><td>Covered (specialist only)</td><td>Specialist pharmacy</td></tr></tbody></table><p>Note: Norway has a high-cost protection scheme (egenandelstak) — once you spend 3,051 NOK (~€260) per year on healthcare, the rest is free.</p><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>NBTS psychological assessment</strong> — Included in care pathway</li><li><strong>FRI</strong> — Peer support groups across Norway</li><li><strong>Harry Benjamin Resource Centre</strong> — Counselling and support</li><li><strong>Private psychologists</strong> — Gender-competent therapists available in major cities</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Helsenorge</strong> — Official health portal: <a href="https://www.helsenorge.no/" target="_blank" rel="noreferrer">helsenorge.no</a></li><li><strong>NBTS - Oslo University Hospital</strong> — <a href="https://www.oslo-universitetssykehus.no/" target="_blank" rel="noreferrer">oslo-universitetssykehus.no</a></li><li><strong>Harry Benjamin Resource Centre</strong> — <a href="https://hbrs.no/" target="_blank" rel="noreferrer">hbrs.no</a></li><li><strong>FRI</strong> — LGBTQ+ organisation: <a href="https://foreningenfri.no/" target="_blank" rel="noreferrer">foreningenfri.no</a></li></ul>',21))])}const N=o(h,[["render",c]]);export{b as __pageData,N as default};
